      <button class="load-more-btn" @click="loadMore">
        {{ isLoading ? '加载中...' : '加载更多' }}
      </button>
    </div>

      <!-- 图片预览遮罩层 -->
      <div v-if="viewerImage" class="image-viewer" @click="closeImageViewer">
        <img :src="viewerImage" alt="预览图片" class="viewer-image" @click.stop />
      </div>
    </template>
